__kernel void 
findK(	long height,
		const knode *knodesD,
		long knodes_elem,
		const record *recordsD,

		long *currKnodeD,
		long *offsetD,
		const int *keysD, 
		record *ansD)
{


	int thid = get_local_id(0);
	int bid = get_group_id(0);


	int i;
	for(i = 0; i < height; i++){


		if(keysD[bid] >= (knodesD[currKnodeD[bid]].keys[thid]) && (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])){



			if(knodes_elem > knodesD[offsetD[bid]].indices[thid]){
				offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
			}
		}
		barrier(CLK_LOCAL_MEM_FENCE);


		if(0 == thid){
			currKnodeD[bid] = offsetD[bid];
		}
		barrier(CLK_LOCAL_MEM_FENCE);

	}



	if(knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]){
		ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
	}

}

